import java.util.*;

public class DatabaseConnectionPool {

    private static volatile DatabaseConnectionPool instance;
    private final int maxConnections;
    private final Queue<String> availableConnections;
    private int borrowedCount = 0;

    private DatabaseConnectionPool(int maxConnections) {
        this.maxConnections = maxConnections;
        this.availableConnections = new LinkedList<>();
        for (int i = 1; i <= maxConnections; i++) {
            availableConnections.offer("conn-" + i);
        }
    }

    public static DatabaseConnectionPool getInstance(int maxConnections) {
        // Implement double-checked locking singleton
        if (instance == null) {
            // TODO: add synchronized block with second null check
        }
        return instance;
    }

    public String borrowConnection() {
        // Return next available connection, or null if none available
        if (!availableConnections.isEmpty()) {
            borrowedCount++;
            return availableConnections.poll();
        }
        return null;
    }

    public void returnConnection(String connection) {
        // Return the connection to the pool
        if (connection != null) {
            availableConnections.offer(connection);
            borrowedCount--;
        }
    }

    public int availableCount() { return availableConnections.size(); }
    public int borrowedCount() { return borrowedCount; }

    public static void main(String[] args) {
        DatabaseConnectionPool pool = DatabaseConnectionPool.getInstance(3);
        String c1 = pool.borrowConnection();
        String c2 = pool.borrowConnection();
        System.out.println("Borrowed: " + pool.borrowedCount());
        System.out.println("Available: " + pool.availableCount());
        pool.returnConnection(c1);
        System.out.println("After return - Available: " + pool.availableCount());
        // Second getInstance call returns same instance
        System.out.println("Same instance: " + (pool == DatabaseConnectionPool.getInstance(5)));
    }
}

import java.util.*;

public class HttpRequest {

    private final String url;
    private final String method;
    private final Map<String, String> headers;
    private final Map<String, String> queryParams;
    private final String body;

    private HttpRequest(Builder builder) {
        this.url = builder.url;
        this.method = builder.method;
        this.headers = Collections.unmodifiableMap(new HashMap<>(builder.headers));
        this.queryParams = Collections.unmodifiableMap(new HashMap<>(builder.queryParams));
        this.body = builder.body;
    }

    public String url() { return url; }
    public String method() { return method; }
    public Map<String, String> headers() { return headers; }
    public String body() { return body; }
    public int headerCount() { return headers.size(); }

    public static class Builder {
        private String url;
        private String method = "GET";
        private final Map<String, String> headers = new LinkedHashMap<>();
        private final Map<String, String> queryParams = new LinkedHashMap<>();
        private String body;

        public Builder url(String url) {
            this.url = url;
            return this;
        }

        public Builder method(String method) {
            this.method = method;
            return this;
        }

        public Builder header(String name, String value) {
            // Add a header to the headers map
            return this;
        }

        public Builder queryParam(String name, String value) {
            // Add a query parameter
            return this;
        }

        public Builder body(String body) {
            this.body = body;
            return this;
        }

        public HttpRequest build() {
            // Validate: url must not be null or blank
            // Validate: body is only allowed for POST/PUT/PATCH
            if (url == null || url.isBlank()) {
                throw new IllegalStateException("URL is required");
            }
            return new HttpRequest(this);
        }
    }

    public static void main(String[] args) {
        HttpRequest request = new HttpRequest.Builder()
            .url("https://api.example.com/users")
            .method("POST")
            .header("Content-Type", "application/json")
            .header("Authorization", "Bearer token123")
            .body("{\"name\": \"Alice\"}")
            .build();

        System.out.println("URL: " + request.url());
        System.out.println("Method: " + request.method());
        System.out.println("Headers: " + request.headerCount());
        System.out.println("Body: " + request.body());
    }
}

